  "type": "module",
  "main": "server.js",
  "license": "MIT",
  "author": "Jo Inc <oss@askjo.ai>",
  "homepage": "https://github.com/jo-inc/camofox-browser#readme",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/jo-inc/camofox-browser.git"
  },
  "bugs": {
    "url": "https://github.com/jo-inc/camofox-browser/issues"
  },
