    "plugin.ts",
    "plugin.js",
    "dist/plugin.js",
    "tsconfig.json",
    "openclaw.plugin.json",
    "bin/",
    "scripts/",
    "run.sh",
    "Dockerfile",
    "README.md",
    "LICENSE",
    "AGENTS.md",
    "!**/*.test.js",
    "!**/*.test.ts",
    "!**/*.spec.js"
  ],
